sql:
SELECT c.customer_id, c.first_name, c.last_name, c.email
FROM customers c
JOIN purchases p ON c.customer_id = p.customer_id;

SELECT segment_size 
FROM campaign_segments 
WHERE segment_name = 'New Customers';

SELECT COUNT(*) 
FROM purchases 
WHERE purchase_id = 0 AND customer_id = 0;

SELECT campaign_name, SUM(actual_spend) AS total_spend
FROM marketing_campaigns
GROUP BY campaign_name;

SELECT COUNT(DISTINCT customer_id) AS loyalty_customer_count
FROM customers
WHERE loyalty_member = 1 AND preferred_channel = 'email' AND state = 'MA';
